$headers = @{
  "Authorization" = "Bearer $token"
  "Accept" = "application/vnd.github.v3+json"
  "Content-Type" = "application/json"
}

function UpdateFile($path, $content64) {
  $url = "https://api.github.com/repos/$repo/contents/$path"
  try { $existing = Invoke-RestMethod -Uri $url -Headers $headers -Method Get; $sha = $existing.sha } catch { $sha = $null }
  $body = @{ message = "feat: landing page, admin dashboard, invoices, pricing"; content = $content64 }
  if ($sha) { $body.sha = $sha }
  Invoke-RestMethod -Uri $url -Headers $headers -Method Put -Body ($body | ConvertTo-Json) | Out-Null
  Write-Host "  ✓ $path"
}

